    bxor = function(a, b)
        local r, p, c = 0, 1, 0
        while a > 0 or b > 0 do
            local ra, rb = a % 2, b % 2
            if ra ~= rb then r = r + p end
            a, b, p = (a-ra)/2, (b-rb)/2, p*2
        end
